-- team). Console Warriors' real rosters + schedule + real scoring, fake team
-- names, a 2025 league logo per team, and a not-on-bye K/DST so Banker/Suppress
-- are playable. Generated by server/scripts/gen-fake-league.mjs. Idempotent.

alter table league_membership add column if not exists avatar_url text;

