  returning id into dst;

  -- clean any prior seed of THIS fake league so re-runs are idempotent
  delete from sealed_pick where matchup_id in (select id from matchup where league_id = dst);
  delete from matchup_state where matchup_id in (select id from matchup where league_id = dst);
